window.__QUIZ_DATA__=[{"id":"objective>Computer Studies>2022>1","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"One-millionth of a second is also referred to as","images":[],"options":{"A":"nanosecond","B":"microsecond","C":"millisecond","D":"picosecond"},"answer":"B","explanation":"One-millionth of a second is referred to as a microsecond. The prefix 'micro' in the metric system denotes a factor of one millionth (10^-6). Therefore, a microsecond is one millionth of a second.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>2","subject":"Computer Studies","year":"2022","type":"Objective","topic":"INFORMATION AGE : DATA AND INFORMATION","question":"Examples of quantitative data type are","images":[],"options":{"A":"continuous and discrete","B":"local and foreign","C":"nominal and ordinal","D":"primary and secondary"},"answer":"A","explanation":"Quantitative data is numerical data that can be measured or counted. It is divided into two types: continuous and discrete. Continuous data can take any value within a range, while discrete data can only take certain values.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>3","subject":"Computer Studies","year":"2022","type":"Objective","topic":"INFORMATION AGE : DATA AND INFORMATION","question":"One difference between data and information is that","images":[],"options":{"A":"data is meaningful while information is not meaningful","B":"data are raw facts and figures while information is computed data","C":"information is independent of data while data is dependent on information","D":"information is the raw material while data is the end product of information"},"answer":"B","explanation":"Data are raw facts and figures, while information is processed data. Data becomes information when it is processed and put into context, providing it with meaning and relevance.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>4","subject":"Computer Studies","year":"2022","type":"Objective","topic":"INFORMATION AGE : DATA AND INFORMATION","question":"The following options are examples of information except","images":[],"options":{"A":"area of a circle","B":"circumference of a circle","C":"perimeter of a rectangle","D":"plain shape of a rectangle"},"answer":"D","explanation":"Information is data that is processed to be useful; it provides answers to 'who', 'what', 'where', and 'how' questions. In this context, 'plain shape of a rectangle' is not an example of information because it does not provide any specific or processed data. The other options provide specific measurements, which can be considered as information.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>5","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : CLASSIFICATION OF COMPUTERS","question":"Modern computers compared to earlier computers are","images":[],"options":{"A":"less reliable","B":"faster and larger","C":"larger and stronger","D":"faster and smaller"},"answer":"D","explanation":"Modern computers are faster and smaller compared to earlier computers. This is due to advancements in technology that have allowed for the miniaturization of components and increased processing power. The other options are incorrect because modern computers are not less reliable, nor are they larger and stronger.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>6","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : CLASSIFICATION OF COMPUTERS","question":"What type of computer would be most suitable for a student who lives in a remote village without constant electricity?","images":[],"options":{"A":"Desktop computer","B":"Laptop computer","C":"Mainframe computer","D":"Mini computer"},"answer":"B","explanation":"A laptop is most suitable for a student in a remote village, can easily be carried around and has enough power backup.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>7","subject":"Computer Studies","year":"2022","type":"Objective","topic":"INFORMATION AGE : HISTORY OF COMPUTERS","question":"EDSAC was produced using a concept known as","images":[],"options":{"A":"Circuit switching","B":"Packet routing","C":"Packet switching","D":"Stored program"},"answer":"D","explanation":"EDSAC, the Electronic Storage Automatic Calculator (EDSAC) was based on John Von Neumann's stored program concept.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>8","subject":"Computer Studies","year":"2022","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM","question":"The process of running more than one program concurrently is known as","images":[],"options":{"A":"multithreading","B":"multitasking","C":"multiprogramming","D":"multipurpose"},"answer":"B","explanation":"Multitasking allows users to run multiple programs at the same time, even if the computer only has one CPU. This is done by switching between the programs very quickly, so that it appears to the user that all of the programs are running at the same time.    Multitasking is a common feature of modern operating systems. It allows users to be more productive by allowing them to run multiple programs at the same time.","marks":"1","difficulty":"3"},{"id":"objective>Computer Studies>2022>9","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"How many binary digits are contained in 10 MB of a memory stick?","images":[],"options":{"A":"10 x 1024","B":"10 x 1024 x 8","C":"10 x 1024 x x1024","D":"10 x 1024 x 1024 x8"},"answer":"D","explanation":"1 byte = 8 bits, 1 KB = 1024 bytes, 1 MB = 1024 KB. Therefore, 10 MB = 10 x 1024 x 1024 x 8 bits. So, the correct answer is '10 x 1024 x 1024 x 8'.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>10","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"A student would require the following devices to fill an online application form except","images":[],"options":{"A":"keyboard","B":"mouse","C":"printer","D":"webcam"},"answer":"C","explanation":"A printer is not needed to fill an online application form, since you may not necessarily need to print, the form is submitted online.  You need mouse and keyboard to input your data and webcam to take passport photograph.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2022>11","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The logic gate in Figure 1 is called","images":["data:image/jpeg;base64,"],"options":{"A":"AND gate","B":"NAND gate","C":"NOR gate","D":"OR gate"},"answer":"A","explanation":"The logic gate is an AND gate, it takes two or more inputs and returns true if they are all true.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>12","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The logic equation for the logic gate in Figure 1  is","images":["data:image/jpeg;base64,"],"options":{"A":"Z = A + B","B":"Z = A.B","C":"Z =bar( A + B)","D":"Z = bar(A.B)"},"answer":"B","explanation":"Z = A.B, AND is denoted by dot or product of the input","marks":"1","difficulty":"3"},{"id":"objective>Computer Studies>2022>13","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The part balled x in Figure 2 is called","images":["data:image/png;base64,"],"options":{"A":"auxiliary memory","B":"output unit","C":"secondary memory","D":"storage unit"},"answer":"B","explanation":"The part labeled as x in Figure 2 is commonly referred to as the output unit in computer systems. The output unit is a fundamental component responsible for presenting the results of processed data to the user or to other systems. It plays a crucial role in the overall functioning of a computer, as it translates the internal operations and calculations into a format that can be easily understood.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>14","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The logic equation for the logic circuit in Figure 3  is","images":["data:image/jpeg;base64,"],"options":{"A":"Z = bar(A + B) + C","B":"Z = bar(A.B) + C","C":"Z = A + B + C","D":"Z = A.B.bar(C)"},"answer":"B","explanation":"Z = bar(A.B.bar(C))  from boolean theorem  if P = bar(X.Y)  P = bar(X) + bar(Y)  Z = bar(A.B) + C","marks":"1","difficulty":"3"},{"id":"objective>Computer Studies>2022>15","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The program that is loaded into a special area on a microprocessor or ROM on a one-time basis and becomes part of the hardware is called","images":[],"options":{"A":"firmware","B":"liveware","C":"software","D":"utility"},"answer":"A","explanation":"Firmware is a computer program that is embedded in a hardware device and is an essential part of the hardware.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>16","subject":"Computer Studies","year":"2022","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES~~TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM~~TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING","question":"The following programs are general purpose application software except","images":[],"options":{"A":"CorelDraw","B":"Payroll system","C":"MS Access","D":"MS Word"},"answer":"B","explanation":"Payroll system is not a general purpose application software, it provides only one feature for the user.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>17","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"One similarity between bespoke software and application packages is that they are","images":[],"options":{"A":"both available off the shelf","B":"highly standardized","C":"both written by computer users","D":"meant to be used by computer end-users"},"answer":"D","explanation":"Bespoke software and application packages are both meant to be used by computer end-users. Bespoke software is custom software tailored to the specific needs of an organization or user, while application packages are pre-written applications available for general use. Both are designed to be used by end-users to perform specific tasks.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2022>18","subject":"Computer Studies","year":"2022","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM","question":"One function of operating system is","images":[],"options":{"A":"power supply allocation","B":"file corruption and deletion","C":"hardware upgrade","D":"resource allocation"},"answer":"D","explanation":"Operating system has other functions like memory management,processor management,file management, security, coordination between other software and users. etc.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>19","subject":"Computer Studies","year":"2022","type":"Objective","topic":"INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING","question":"The process of testing the logic of algorithm to ensure they give correct result is known as","images":[],"options":{"A":"debugging","B":"desk checking","C":"flowcharting","D":"pseudo-coding"},"answer":"B","explanation":"A desk check is an informal non-computerized or manual process for verifying the programming and logic of an algorithm before the program is launched.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>20","subject":"Computer Studies","year":"2022","type":"Objective","topic":"INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING","question":"The following instructions are guidelines for drawing flowcharts  except that","images":[],"options":{"A":"flowcharts must have logical start and finish","B":"it should follow a direction of left to right or top to bottom","C":"it should follow a direction of right to left or bottom to top","D":"it should be clear, neat and easy to follow"},"answer":"C","explanation":"Flowcharts are graphical representations of a process. They are typically drawn from left to right or top to bottom to represent the flow of control. The option 'it should follow a direction of right to left or bottom to top' is incorrect because it contradicts the standard direction of flow in a flowchart.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>21","subject":"Computer Studies","year":"2022","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : CAREER OPPORTUNITIES IN DATA PROCESSING","question":"Key skills of a system analyst include the following except","images":[],"options":{"A":"ability to troubleshoot","B":"interest in learning new skills","C":"motivational skills","D":"proficiency in programming languages"},"answer":"C","explanation":"A system analyst does not need a motivational skills","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>22","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"The result of the expression 2*6 + 2/4*2*4^2 is","images":[],"options":{"A":"21","B":"27","C":"28","D":"29"},"answer":"C","explanation":"2\u00d76 + 2/4\u00d72\u00d742 = 28    Therefore, the result of the expression is 28","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>23","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"Use the QBASIC program below to answer the following question      10 REM Program to calculate of numbers    20 CLS    30 IMPUT A\t    40 IMPUTE B    50 LET PRODUCT = A * B     60 PRINT PRODUCT    70 END    The numbers 10, 20, 30, 40, 50, 60 and 70 as stated in the program indicate","images":[],"options":{"A":"bullet numbering","B":"codes","C":"labels","D":"line numbers"},"answer":"D","explanation":"In QBASIC, the numbers 10, 20, 30, 40, 50, 60, and 70 are line numbers. They are used to organize the code and control the flow of the program. Each line number is followed by a QBASIC statement or command. The program executes these commands in the order of their line numbers.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>24","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"The QBASIC statement LET X = Y - 3 means","images":[],"options":{"A":"the variables X and Y both receive the value 3","B":"the variable X receives the value 3","C":"the variable X receives the value of Y less 3","D":"an error message has occurred due to type mismatch"},"answer":"C","explanation":"In QBASIC, the statement 'LET X = Y - 3' means that the variable X is assigned the value of Y minus 3. The 'LET' keyword is used to assign a value to a variable. In this case, the value of Y is reduced by 3 and the result is stored in the variable X.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>25","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The part labelled Y  in the compiler interface in Figure 4  represents","images":["data:image/png;base64,"],"options":{"A":"intermediate code","B":"binary code","C":"object code","D":"pseudo code"},"answer":"B","explanation":"Compilers translate source codes to machine codes which are binary codes","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>26","subject":"Computer Studies","year":"2022","type":"Objective","topic":"INFORMATION TRANSMISSION : INTERNET","question":"The virtual communication platform where many people keep in contact with family and friends is known as","images":[],"options":{"A":"Microsoft Visio","B":"social engineering","C":"cyberspace","D":"virtual reality"},"answer":"C","explanation":"Cyberspace is a concept describing a widespread interconnected digital technology","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2022>27","subject":"Computer Studies","year":"2022","type":"Objective","topic":"INFORMATION TRANSMISSION : INTERNET","question":"The protocol used for email transmission is known as","images":[],"options":{"A":"HTTPS","B":"DHCP","C":"IP","D":"SMTP"},"answer":"D","explanation":"SMTP. The Simple Mail Transfer Protocol (SMTP) is used for sending and receiving e-mail between e-mail clients and servers.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2022>28","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The signals from computer A to modem X in Figure 5 are","images":["data:image/jpeg;base64,"],"options":{"A":"analogue","B":"digital","C":"electrons","D":"protons"},"answer":"B","explanation":"A digital signal is a signal that represents data using a sequence of discrete values, such as 0s and 1s. Digital signals are used in computers, digital phones, and other technological devices.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>29","subject":"Computer Studies","year":"2022","type":"Objective","topic":"INFORMATION TRANSMISSION : NETWORKING","question":"What type of network is represented in Figure 6?","images":["data:image/png;base64,"],"options":{"A":"Local Area Network","B":"Metropolitan Area Network","C":"Personal Area Network","D":"Wide Area Network"},"answer":"D","explanation":"A wide area network (WAN) is a large computer network that connects groups of computers over large distances. WANs are often used by large businesses to connect their office networks; each office typically has its own local area network, or LAN, and these LANs connect via a WAN.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2022>30","subject":"Computer Studies","year":"2022","type":"Objective","topic":"INFORMATION TRANSMISSION : INTERNET","question":"In the URL https://www.waec.org.ng, the domain name is","images":[],"options":{"A":"waec.org.ng.","B":"https://www.","C":"//www.waec.","D":".org.ng."},"answer":"A","explanation":"A domain name (or just 'domain') is the name of a website. It's what comes after \"@\" in an email address, or after \"www.\" in a web address.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2022>31","subject":"Computer Studies","year":"2022","type":"Objective","topic":"INFORMATION TRANSMISSION : PROCESS OF INFORMATION TRANSMISSION","question":"The type of transmission in the part labelled Q in Figure 7 is called","images":["data:image/jpeg;base64,"],"options":{"A":"broadcast","B":"full duplex","C":"half duplex","D":"simplex"},"answer":"B","explanation":"In full-duplex mode, both stations can transmit and receive simultaneously.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>32","subject":"Computer Studies","year":"2022","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM","question":"The maximum length of a text field in MS Access is","images":[],"options":{"A":"75","B":"120","C":"255","D":"265"},"answer":"C","explanation":"The maximum length of a text field in MS Access is 255 characters.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2022>33","subject":"Computer Studies","year":"2022","type":"Objective","topic":"DATA MANAGEMENT : RELATIONAL MODEL","question":"The number of entries in Figure below is","images":["data:image/jpeg;base64,"],"options":{"A":"3","B":"4","C":"5","D":"12"},"answer":"B","explanation":"The number of entries in Figure above is four (4).","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2022>34","subject":"Computer Studies","year":"2022","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING","question":"The shortcut key for the Open dialog box in MS word is","images":[],"options":{"A":"Alt + F12","B":"Ctrl + F12","C":"F12","D":"Shift + F12"},"answer":"B","explanation":"The shortcut key for the Open dialog box in MS Word is Ctrl + F12. This command opens the Open dialog box where you can select a file to open.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2022>35","subject":"Computer Studies","year":"2022","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES","question":"The part of the CorelDraw window labelled II in Figure 9  is called","images":["data:image/jpeg;base64,"],"options":{"A":"Pan","B":"Zoom In","C":"Zoom Out","D":"Zoom to fit"},"answer":"A","explanation":"pan tools let you move the page around in the drawing window to view previously hidden areas.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2022>36","subject":"Computer Studies","year":"2022","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : PRESENTATION PACKAGE","question":"Which of the following operations will not  run a slide show in MS PowerPoint?","images":[],"options":{"A":"Pressing F5","B":"Pressing Shift + F5","C":"Choosing the slide show tab","D":"Clicking the slide show on the taskbar"},"answer":"D","explanation":"Clicking the slide show on the taskbar will not run a slide show in MS PowerPoint. The taskbar is a component of an operating system's graphical user interface which serves as the housing for tasks and notifications related to open programs. Pressing F5, Pressing Shift + F5, and Choosing the slide show tab are all correct ways to start a slide show in PowerPoint.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2022>37","subject":"Computer Studies","year":"2022","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : SPREADSHEET","question":"What will be the result of writing the formula =Year(now()) + 3 in a worksheet of a spreadsheet, if the current calendar date is  14 August, 1960?","images":[],"options":{"A":"17 August, 1960 03.00","B":"14 August, 1963","C":"11 August, 1963","D":"1963"},"answer":"D","explanation":"The formula =Year(now()) + 3 in a worksheet of a spreadsheet will return the current year plus 3. If the current calendar date is 14 August, 1960, the formula will return 1963. The Year function returns the year of a date as a four digit number, the Now function returns the current date and time, and the '+' operator adds 3 to the year.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>38","subject":"Computer Studies","year":"2022","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : SPREADSHEET","question":"If A is in cell A1 and B is cell B1 of a worksheet in a spreadsheet application, write a formula  tocalculateX=A2+B1/2100","images":[],"options":{"A":"((A1^2) + (B11/2))/100","B":"((A1^2 + (B11/2))/100","C":"((A1^2 + (B11/2)/100","D":"((A1^2 + (B1^1/2)))/100"},"answer":"A","explanation":"The formula is given below:    ((A1^2) + (B11/2))/100","marks":"1","difficulty":"3"},{"id":"objective>Computer Studies>2022>39","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"The pictorial representation of an object or application in the computer is called","images":[],"options":{"A":"diagram","B":"graphic","C":"icon","D":"image"},"answer":"C","explanation":"An icon is an image on the computer screen that represents an application, a capability, or some other concept or specific entity with meaning for the user.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2022>40","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"Deleted items in the computer are temporarily stored in the","images":[],"options":{"A":"memory unit","B":"processor","C":"recycle bin","D":"task manager"},"answer":"C","explanation":"When you delete items on a computer, they are not immediately removed from the system. Instead, they are moved to a special folder called the Recycle Bin. This allows you to recover files if you accidentally delete them. The items remain in the Recycle Bin until you manually empty it, or until the system automatically does so to free up disk space.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2022>41","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"The keyboard key combination ALT + F4 in Microsoft Windows will","images":[],"options":{"A":"close active programmes","B":"open a file","C":"restart the computer","D":"save all active files"},"answer":"A","explanation":"The keyboard key combination ALT + F4 in Microsoft Windows is used to close the active program. This is a shortcut command that is commonly used in Windows operating systems to quickly close an application or window.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2022>42","subject":"Computer Studies","year":"2022","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM","question":"Select two stages of booting from the following list:  I.\tPower on Self Test;  II.\tLoading of Operating System;  III.\tLoading of e-mails;  IV.\tStart in safe mode.","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and IV only","D":"III and IV only"},"answer":"A","explanation":"Stages of booting  The Startup. It is the first step that involves switching the power ON. ...  BIOS: Power On Self Test. It is an initial test performed by the BIOS. ...  Loading of OS.  System Configuration.  Loading System Utilities.  User Authentication","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>43","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : CLASSIFICATION OF COMPUTERS","question":"In number system, base 16 is called","images":[],"options":{"A":"hexadecimal","B":"decimal","C":"duodecimal","D":"octal"},"answer":"A","explanation":"In number systems, base 16 is called hexadecimal. The hexadecimal system is a base 16 number system that uses sixteen distinct symbols, typically the symbols 0\u20139 to represent values zero to nine, and A, B, C, D, E, F (or alternatively a\u2013f) to represent values ten to fifteen.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2022>44","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : CLASSIFICATION OF COMPUTERS","question":"Add 12716 to 50A16","images":[],"options":{"A":"62916","B":"63016","C":"63116","D":"63216"},"answer":"C","explanation":"1 2 75 0 A6 3 1    A = 10, 10+7 = 17  17 -16 = 1, write 1 and add 16/16 = 1 to 2 which is = 3 and 5+1 = 6","marks":"1","difficulty":"3"},{"id":"objective>Computer Studies>2022>45","subject":"Computer Studies","year":"2022","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The octal fraction 0.65 converts to binary as","images":[],"options":{"A":"0.110011","B":"0.110101","C":"101101","D":"101110"},"answer":"B","explanation":"convert 0.658 to decimal  6 \u00d7 8-1 + 5 \u00d7 8-2 = 6 \u00d7 1/8 + 5 \u00d7 1/64  5364  5364tobinary  5364=0.828125  0.828125 \u00d7 2 = 1.65625 10.65625 \u00d7 2 = 1.3125 10.3125 \u00d7 2 = 0.625 00.625 \u00d7 2 = 1.25 10.25 \u00d7 2 = 0.50 00.50 \u00d7 2 = 1 1  0.110101  Note: when converting fraction to binary, you write from top to bottom.","marks":"1","difficulty":"3"},{"id":"objective>Computer Studies>2022>46","subject":"Computer Studies","year":"2022","type":"Objective","topic":"DATA MANAGEMENT : FILE ORGANIZATION","question":"Sequential files are","images":[],"options":{"A":"sorted using index","B":"sorted in a particular order","C":"stored as they come","D":"stored in any storage media"},"answer":"B","explanation":"Sequential files contain records that are sorted and stored in an ascending or descending order on a particular key field.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>47","subject":"Computer Studies","year":"2022","type":"Objective","topic":"DATA MANAGEMENT : FILE ORGANIZATION","question":"The file access method illustrated in Figure 10 is called","images":["data:image/jpeg;base64,"],"options":{"A":"hashed access","B":"indexed access","C":"random access","D":"sequential access"},"answer":"C","explanation":"A random access data file enables you to read or write information anywhere in the file.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>48","subject":"Computer Studies","year":"2022","type":"Objective","topic":"DATA MANAGEMENT : FILE ORGANIZATION","question":"Serial files are","images":[],"options":{"A":"sorted using a key","B":"sorted in a particular order","C":"stored as they come","D":"stored in any storage media"},"answer":"C","explanation":"Serial files are stored as they come. This means that they are stored in the order they are received, without any sorting or reordering. This is different from sequential files, which are sorted in a particular order.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>49","subject":"Computer Studies","year":"2022","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : COMPUTER ETHICS","question":"Duplicating copyrighted electronic or digital content without the author's approval is considered","images":[],"options":{"A":"felonious","B":"ethical","C":"treasonable","D":"unethical"},"answer":"D","explanation":"Duplicating copyrighted electronic or digital content without the author's approval is considered unethical.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2022>50","subject":"Computer Studies","year":"2022","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : COMPUTER ETHICS","question":"Ethical practice requires a computer user to","images":[],"options":{"A":"shutdown properly after using the computer","B":"hack into other people's computer","C":"intrude into people's privacy","D":"copy software without the license"},"answer":"A","explanation":"The Ten Commandments of computer ethics as defined by the Computer Ethics  Institute.  1) Thou shalt not use a computer to harm other people:  2) Thou shalt not interfere with other people's computer work:  3) Thou shalt not snoop around in other people's files:  4) Thou shalt not use a computer to steal:  5) Thou shalt not use a computer to bear false witness:  6) Thou shalt not use or copy software for which you have not paid:  7) Thou shalt not use other people's computer resources without authorization:  8) Thou shalt not appropriate other people's intellectual output:  9) Thou shalt think about the social consequences of the program you write:  10) Thou shalt use a computer in ways that show consideration and respect:","marks":"1","difficulty":"1"}];